#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        unsigned long long N; scanf("%llu",&N);
        int cnt=0;
        while(N){ N/=10; cnt++; }
        printf("%d\n",cnt);
    }
    return 0;
}

